 60→    showRoomDimensions: overrides.showRoomDimensions ?? true,
 61→    showOverallDimensions: overrides.showOverallDimensions ?? true,
 62→    showObjectTags: overrides.showObjectTags ?? true,
 63→    showElevationOverallDimensions: overrides.showElevationOverallDimensions ?? true,
 64→    showElevationLevelDimensions: overrides.showElevationLevelDimensions ?? true,
 65→    showElevationOpeningDimensions: overrides.showElevationOpeningDimensions ?? true,
 66→  };
