493→
494→    case 'UNDO': {
495→      if (state.history.length === 0) return state;
496→      const previousProject = state.history[state.history.length - 1];
497→      return {
498→        ...state,
499→        project: previousProject,
500→        history: state.history.slice(0, -1),
501→        future: [state.project, ...state.future].slice(0, HISTORY_LIMIT),
502→        isDirty: snapshotProject(previousProject) !== state.savedSnapshot,
