508→      const nextProject = state.future[0];
509→      return {
510→        ...state,
511→        project: nextProject,
512→        history: [...state.history, state.project].slice(-HISTORY_LIMIT),
513→        future: state.future.slice(1),
514→        isDirty: snapshotProject(nextProject) !== state.savedSnapshot,
515→      };
516→    }
517→
518→    default:
519→      return state;
520→  }
521→}
