 11→function WallSelection({ wall, columns, zoom }) {
 12→  const outline = getWallRenderData(wall, columns || []).outline;
 13→  const points = outline.map(p => `${p.x},${p.y}`).join(' ');
 14→  const handleR = HANDLE_SIZE / zoom;
 15→
 16→  return (
 17→    <g>
 18→      <polygon
 19→        points={points}
 20→        fill="var(--color-selection-fill)"
 21→        stroke="var(--color-selection)"
 22→        strokeWidth={2}
 23→        strokeDasharray="6 3"
 24→        vectorEffect="non-scaling-stroke"
 25→      />
 26→      {/* Endpoint handles */}
 27→      <rect
 28→        data-handle="start"
 29→        x={wall.start.x - handleR / 2}
 30→        y={wall.start.y - handleR / 2}
 31→        width={handleR}
 32→        height={handleR}
 33→        fill="white"
 34→        stroke="var(--color-selection)"
 35→        strokeWidth={2}
 36→        vectorEffect="non-scaling-stroke"
 37→        style={{ cursor: 'move' }}
 38→      />
 39→      <rect
 40→        data-handle="end"
 41→        x={wall.end.x - handleR / 2}
 42→        y={wall.end.y - handleR / 2}
 43→        width={handleR}
 44→        height={handleR}
 45→        fill="white"
 46→        stroke="var(--color-selection)"
 47→        strokeWidth={2}
 48→        vectorEffect="non-scaling-stroke"
 49→        style={{ cursor: 'move' }}
 50→      />
 51→    </g>
 52→  );
 53→}
