29→export function useEditorTool({ activeTool, dispatch, editorDispatch, getFloor, activeFloorId, viewport, snapEnabled, selectedId, selectedType, toolState, viewMode }) {
30→  const getFloorRef = useRef(getFloor);
31→  getFloorRef.current = getFloor;
32→
33→  const handler = useMemo(() => {
34→    if (viewMode?.startsWith('elevation_')) {
35→      return createElevationSelectHandler({
36→        dispatch,
37→        editorDispatch,
38→        getFloor: (...args) => getFloorRef.current(...args),
39→        activeFloorId,
40→        viewport,
41→        snapEnabled,
42→        viewMode,
43→      });
44→    }
45→
46→    if (viewMode !== 'plan') {
47→      return createReadOnlyHandler();
48→    }
49→
50→    const ctx = {
51→      dispatch, editorDispatch,
52→      getFloor: (...args) => getFloorRef.current(...args),
53→      activeFloorId, viewport, snapEnabled,
54→    };
55→
56→    switch (activeTool) {
57→      case TOOLS.DIMENSION:
58→        return createDimensionPlaceHandler(ctx);
59→      case TOOLS.WALL:
60→        return createWallDrawHandler(ctx);
61→      case TOOLS.BEAM:
62→        return createBeamPlaceHandler(ctx);
63→      case TOOLS.STAIR:
64→        return createStairPlaceHandler(ctx);
65→      case TOOLS.SECTION:
66→        return createSectionPlaceHandler(ctx);
67→      case TOOLS.SLAB:
68→        return createSlabPlaceHandler(ctx);
69→      case TOOLS.ROOM:
70→        return createRoomPlaceHandler(ctx);
71→      case TOOLS.SELECT:
72→        return createSelectHandler(ctx);
73→      case TOOLS.DOOR:
74→        return createDoorPlaceHandler(ctx);
75→      case TOOLS.WINDOW:
76→        return createWindowPlaceHandler(ctx);
77→      case TOOLS.COLUMN:
78→        return createColumnPlaceHandler(ctx);
79→      default:
80→        return null;
81→    }
82→  }, [activeTool, activeFloorId, viewport.zoom, snapEnabled, viewMode]);
83→
84→  return {
85→    onMouseDown: (modelPos, e) => handler?.onMouseDown?.(modelPos, e, toolState),
86→    onMouseMove: (modelPos, e) => handler?.onMouseMove?.(modelPos, e, toolState, selectedId, selectedType),
87→    onMouseUp: (modelPos, e) => handler?.onMouseUp?.(modelPos, e, toolState),
88→    onDoubleClick: (modelPos, e) => handler?.onDoubleClick?.(modelPos, e, toolState),
89→    onKeyDown: (e) => handler?.onKeyDown?.(e, toolState, selectedId, selectedType),
90→    getCursor: () => handler?.getCursor?.(toolState) || 'default',
91→  };
92→}
