 38→function screenToModel(screenX, screenY, viewport, svgRect) {
 39→  const x = (screenX - svgRect.left - viewport.panX) / viewport.zoom;
 40→  const y = (screenY - svgRect.top - viewport.panY) / viewport.zoom;
 41→  return { x, y };
 42→}
